import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function GET() {
  const templates = await prisma.template.findMany({
    where: { isApproved: true },
    orderBy: { createdAt: "desc" },
  });

  return NextResponse.json(templates);
}

import LZString from "lz-string";
import type { BeadState, SerializableDesign } from "@/types/bead";

/**
 * Encode an array of BeadState objects into a URL-safe design code.
 *
 * Pipeline: filter beads with catalogBeadId → JSON.stringify → LZ-String compress → base64url.
 * Only beads that have a `catalogBeadId` are included; others are silently skipped.
 */
export function encodeDesign(beads: BeadState[]): string {
  const catalogIds = beads
    .filter((b) => b.catalogBeadId)
    .map((b) => b.catalogBeadId as string);

  const design: SerializableDesign = {
    v: 1,
    p: "pacifier-holder",
    b: catalogIds,
  };

  return LZString.compressToEncodedURIComponent(JSON.stringify(design));
}

/**
 * Decode a URL-safe design code back into a SerializableDesign.
 *
 * Applies `decodeURIComponent` first because lz-string output may contain
 * `+` which browsers encode as `%2B` in URL path segments, and Next.js
 * does not decode `%2B` back to `+` in dynamic route params.
 *
 * Returns `null` for any invalid input: malformed base64url, invalid JSON,
 * missing required fields, or unsupported version.
 */
export function decodeDesign(code: string): SerializableDesign | null {
  if (!code || typeof code !== "string") return null;

  try {
    // Normalize URL-encoded characters (e.g. %2B → +) that may appear
    // when design codes are embedded in URL path segments.
    const normalized = decodeURIComponent(code);

    const json = LZString.decompressFromEncodedURIComponent(normalized);
    if (!json) return null;

    const parsed: unknown = JSON.parse(json);

    const obj = parsed as Record<string, unknown>;
    if (obj.v !== 1 || typeof obj.p !== "string" || !Array.isArray(obj.b)) {
      return null;
    }
    if (!(obj.b as unknown[]).every((id) => typeof id === "string")) {
      return null;
    }

    return parsed as SerializableDesign;
  } catch {
    return null;
  }
}

import { PrismaClient } from "@prisma/client";
import { PrismaLibSql } from "@prisma/adapter-libsql";

const globalForPrisma = globalThis as unknown as { prisma: PrismaClient };

function createPrismaClient() {
  const adapter = new PrismaLibSql({
    url: process.env.DATABASE_URL!,
  });
  return new PrismaClient({ adapter });
}

export const prisma = globalForPrisma.prisma || createPrismaClient();

if (process.env.NODE_ENV !== "production") globalForPrisma.prisma = prisma;

import { create } from "zustand";
import type { BeadState } from "@/types/bead";
import { CATALOG_BEADS, getCatalogBead } from "@/data/catalogBeads";
import { catalogBeadToBeadState } from "@/lib/catalogUtils";

// ── Default chain ────────────────────────────────────────────────────────────
// Same 7 default beads as useBeadChain's DEFAULT_BEADS.

const DEFAULT_BEADS: BeadState[] = [
  { id: "bead-1", type: "wood", radius: 0.2, color: "#D4A574" },
  { id: "bead-2", type: "silicone", radius: 0.18, color: "#FF6B9D" },
  { id: "bead-3", type: "wood", radius: 0.22, color: "#C4956A" },
  { id: "bead-4", type: "plastic", radius: 0.19, color: "#6EC1E4" },
  { id: "bead-5", type: "wood", radius: 0.21, color: "#B8860B" },
  { id: "bead-6", type: "silicone", radius: 0.17, color: "#E8A0BF" },
  { id: "bead-7", type: "wood", radius: 0.2, color: "#DEB887" },
];

const MAX_CHAIN_LENGTH = 40;

// ── Store interface ──────────────────────────────────────────────────────────

export interface DesignState {
  beads: BeadState[];
  selectedBeadId: string | null;
  productType: "pacifier-holder";

  addBead: (catalogBeadId: string) => void;
  removeBead: (id: string) => void;
  removeSelected: () => void;
  selectBead: (id: string | null) => void;
  resetDesign: () => void;
  loadFromCatalogIds: (ids: string[]) => void;
  clearDesign: () => void;
}

// ── Store ────────────────────────────────────────────────────────────────────

export const useDesignStore = create<DesignState>((set, get) => ({
  beads: DEFAULT_BEADS,
  selectedBeadId: null,
  productType: "pacifier-holder",

  addBead: (catalogBeadId: string) => {
    if (get().beads.length >= MAX_CHAIN_LENGTH) return;

    const catalogBead = CATALOG_BEADS.find((b) => b.id === catalogBeadId);
    if (!catalogBead) return;

    const beadState = catalogBeadToBeadState(catalogBead);
    set((state) => ({ beads: [...state.beads, beadState] }));
  },

  removeBead: (id: string) => {
    set((state) => {
      const removed = state.beads.find((b) => b.id === id);
      return {
        beads: state.beads.filter((b) => b.id !== id),
        selectedBeadId: removed?.id === state.selectedBeadId ? null : state.selectedBeadId,
      };
    });
  },

  removeSelected: () => {
    const { selectedBeadId } = get();
    if (!selectedBeadId) return;

    set((state) => ({
      beads: state.beads.filter((b) => b.id !== selectedBeadId),
      selectedBeadId: null,
    }));
  },

  selectBead: (id: string | null) => {
    set({ selectedBeadId: id });
  },

  resetDesign: () => {
    set({ beads: DEFAULT_BEADS, selectedBeadId: null });
  },

  loadFromCatalogIds: (ids: string[]) => {
    const beads: BeadState[] = [];
    for (const id of ids) {
      const catalogBead = getCatalogBead(id);
      if (catalogBead) {
        beads.push(catalogBeadToBeadState(catalogBead));
      }
    }
    set({ beads, selectedBeadId: null });
  },

  clearDesign: () => {
    set({ beads: [], selectedBeadId: null });
  },
}));

/// <reference types="vitest/config" />
import { defineConfig } from "vitest/config";
import react from "@vitejs/plugin-react";
import path from "path";
import fs from "fs";

// Resolve the real filesystem path (worktrees may be NTFS junctions / symlinks)
const realRoot = fs.realpathSync(path.resolve(__dirname));

export default defineConfig({
  plugins: [react()],
  resolve: {
    alias: {
      "@": path.resolve(realRoot, "src"),
    },
  },
  server: {
    fs: {
      allow: [realRoot],
    },
  },
  test: {
    environment: "jsdom",
    setupFiles: [path.resolve(realRoot, "src/test-setup.ts")],
    passWithNoTests: true,
  },
});

export type BeadId = string;
export type BeadType = "wood" | "silicone" | "knit" | "plastic";
export type BeadShape = "sphere" | "disc" | "star" | "heart" | "cylinder";

export interface CatalogBead {
  id: string;
  name: string;
  nameRu: string;
  shape: BeadShape;
  size: number;
  material: BeadType;
  color: string;
  secondaryColor?: string;
}

export interface BeadState {
  id: BeadId;
  type: BeadType;
  radius: number;
  color: string;
  catalogBeadId?: string;
}

export interface ChainConfig {
  anchorPosition: [number, number, number];
  gravity: [number, number, number];
}

export interface ChainState {
  beads: BeadState[];
  config: ChainConfig;
}

/** Wire format for design serialization (JSON → LZ-String → base64url). */
export interface SerializableDesign {
  v: 1;
  p: "pacifier-holder";
  b: string[]; // catalogBeadId strings
}

import { describe, it, expect } from "vitest";
import { encodeDesign, decodeDesign } from "../serialization";
import type { BeadState } from "@/types/bead";

// ── Helpers ─────────────────────────────────────────────────────────────────

function makeBead(catalogBeadId: string, overrides?: Partial<BeadState>): BeadState {
  return {
    id: `test-${Math.random().toString(36).slice(2, 8)}`,
    type: "wood",
    radius: 0.2,
    color: "#D4A574",
    catalogBeadId,
    ...overrides,
  };
}

// ── Round-trip tests ────────────────────────────────────────────────────────

describe("encodeDesign / decodeDesign — round-trip", () => {
  it("round-trips 1 bead", () => {
    const beads = [makeBead("cb-001")];
    const code = encodeDesign(beads);
    const decoded = decodeDesign(code);

    expect(decoded).not.toBeNull();
    expect(decoded!.b).toEqual(["cb-001"]);
  });

  it("round-trips 7 beads preserving order", () => {
    const ids = ["cb-001", "cb-026", "cb-051", "cb-076", "cb-010", "cb-050", "cb-100"];
    const beads = ids.map((id) => makeBead(id));
    const code = encodeDesign(beads);
    const decoded = decodeDesign(code);

    expect(decoded).not.toBeNull();
    expect(decoded!.b).toEqual(ids);
  });

  it("round-trips 40 beads", () => {
    const ids = Array.from({ length: 40 }, (_, i) => `cb-${String(i + 1).padStart(3, "0")}`);
    const beads = ids.map((id) => makeBead(id));
    const code = encodeDesign(beads);
    const decoded = decodeDesign(code);

    expect(decoded).not.toBeNull();
    expect(decoded!.b).toEqual(ids);
  });
});

// ── Error handling ──────────────────────────────────────────────────────────

describe("decodeDesign — invalid input returns null", () => {
  it("returns null for a random string", () => {
    expect(decodeDesign("this-is-not-a-valid-design-code")).toBeNull();
  });

  it("returns null for empty string", () => {
    expect(decodeDesign("")).toBeNull();
  });

  it("returns null for truncated base64url", () => {
    const code = encodeDesign([makeBead("cb-001")]);
    // Truncate to half
    expect(decodeDesign(code.slice(0, Math.floor(code.length / 2)))).toBeNull();
  });

  it("returns null for null/undefined-like input", () => {
    // TypeScript wouldn't allow this but test the runtime guard
    expect(decodeDesign(null as unknown as string)).toBeNull();
    expect(decodeDesign(undefined as unknown as string)).toBeNull();
  });
});

// ── Encoding edge cases ─────────────────────────────────────────────────────

describe("encodeDesign — filtering", () => {
  it("skips beads without catalogBeadId", () => {
    const beads: BeadState[] = [
      makeBead("cb-001"),
      { id: "manual-1", type: "wood", radius: 0.2, color: "#FF0000" }, // no catalogBeadId
      makeBead("cb-026"),
    ];
    const code = encodeDesign(beads);
    const decoded = decodeDesign(code);

    expect(decoded).not.toBeNull();
    expect(decoded!.b).toEqual(["cb-001", "cb-026"]);
  });

  it("returns valid code for empty bead array", () => {
    const code = encodeDesign([]);
    const decoded = decodeDesign(code);

    expect(decoded).not.toBeNull();
    expect(decoded!.b).toEqual([]);
  });
});

// ── Structure validation ────────────────────────────────────────────────────

describe("SerializableDesign structure", () => {
  it("version field is 1", () => {
    const code = encodeDesign([makeBead("cb-001")]);
    const decoded = decodeDesign(code);

    expect(decoded!.v).toBe(1);
  });

  it("productType is pacifier-holder", () => {
    const code = encodeDesign([makeBead("cb-001")]);
    const decoded = decodeDesign(code);

    expect(decoded!.p).toBe("pacifier-holder");
  });

  it("encoded code is URL-safe (no +, /, = characters)", () => {
    const code = encodeDesign([makeBead("cb-001")]);
    expect(code).not.toMatch(/[+/=]/);
  });

  it("encoded code is non-empty", () => {
    const code = encodeDesign([makeBead("cb-001")]);
    expect(code.length).toBeGreaterThan(0);
  });
});

